// Collect context from whichever trigger fired
const input = $input.all();
const errorData = input[0]?.json || {};

const isErrorTrigger = !!errorData.execution;
const now = new Date();
const fourHoursAgo = new Date(now.getTime() - 4 * 60 * 60 * 1000);

return [{
  json: {
    source: isErrorTrigger ? 'error-trigger' : 'scheduled',
    timestamp: now.toISOString(),
    lookbackFrom: fourHoursAgo.toISOString(),
    errorContext: isErrorTrigger ? {
      workflowId: errorData.execution?.workflowId,
      workflowName: errorData.execution?.workflowData?.name,
      executionId: errorData.execution?.id,
      errorMessage: errorData.execution?.error?.message,
      errorNode: errorData.execution?.error?.node?.name,
      lastNodeExecuted: errorData.execution?.lastNodeExecuted,
    } : null
  }
}];

// Merge error context with recent failures
const context = $('Collect Error Context').first().json;
const execResponse = $input.first().json;

const recentFailures = (execResponse.data || []).slice(0, 10);

const summary = recentFailures.map(ex => ({
  id: ex.id,
  workflowName: ex.workflowData?.name || 'unknown',
  error: ex.data?.resultData?.error?.message || 'no message',
  failedNode: ex.data?.resultData?.lastNodeExecuted || 'unknown',
  finishedAt: ex.stoppedAt,
}));

const diagnosisInput = {
  source: context.source,
  directError: context.errorContext,
  recentFailures: summary,
  failureCount: summary.length,
  timestamp: context.timestamp,
};

return [{ json: diagnosisInput }];

// Parse Ollama response and extract diagnosis
const raw = $input.first().json;
let diagnosis;

try {
  const responseText = raw.response || '';
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    diagnosis = JSON.parse(jsonMatch[0]);
  } else {
    diagnosis = { rootCause: 'Could not parse Ollama response', confidence: 0, risk: 'high', needsHumanReview: true, suggestedAction: 'alert_human' };
  }
} catch (e) {
  diagnosis = { rootCause: 'JSON parse error: ' + e.message, confidence: 0, risk: 'high', needsHumanReview: true, suggestedAction: 'alert_human' };
}

diagnosis.analyzedAt = new Date().toISOString();

return [{ json: diagnosis }];

